class Solution {
    public int longestSubsequence(String s, int k) {
        int n = s.length();
        int[] dp = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            dp[i] = dp[i - 1];
            if (Integer.parseInt(s.substring(0, i), 2) <= k) {
                dp[i] = Math.max(dp[i], i);
            }
            for (int j = 1; j < i; j++) {
                if (Integer.parseInt(s.substring(j, i), 2) <= k) {
                    dp[i] = Math.max(dp[i], dp[j] + i - j);
                }
            }
        }
        return dp[n];
    }
}
